#include "Storage.h"
#include "../config/BuildConfig.h"
bool Storage::begin(Stats&s){if(!prefs.begin("reflex",false)){DEBUGF("Preferences open failed\n");return false;} settings.sound=prefs.getBool("sound",true);settings.led=prefs.getBool("led",true);settings.length=prefs.getUChar("length",1);settings.quickTrials=prefs.getUChar("trials",10);settings.lapseMs=prefs.getUShort("lapse",500);s.sessions=prefs.getULong("sessions",0);s.personalBest=prefs.getUShort("best",0);s.scoreCount=prefs.getUChar("scoreN",0);prefs.getBytes("scores",s.scores,sizeof(s.scores));prefs.getBytes("last",&s.last,sizeof(s.last));s.baseline.quickSamples=prefs.getUChar("qN",0);s.baseline.quickMedian=prefs.getFloat("qMed",0);s.baseline.quickSpread=prefs.getFloat("qDev",0);s.baseline.quickLapseRate=prefs.getFloat("qLap",0);s.baseline.focusMedian=prefs.getFloat("fMed",0);s.baseline.focusLapseRate=prefs.getFloat("fLap",0);s.baseline.rhythmError=prefs.getFloat("rErr",0);DEBUGF("Loaded baseline quick=%u %.1f\n",s.baseline.quickSamples,s.baseline.quickMedian);return true;}
void Storage::save(const Stats&s){prefs.putULong("sessions",s.sessions);prefs.putUShort("best",s.personalBest);prefs.putUChar("scoreN",s.scoreCount);prefs.putBytes("scores",s.scores,sizeof(s.scores));prefs.putBytes("last",&s.last,sizeof(s.last));prefs.putUChar("qN",s.baseline.quickSamples);prefs.putFloat("qMed",s.baseline.quickMedian);prefs.putFloat("qDev",s.baseline.quickSpread);prefs.putFloat("qLap",s.baseline.quickLapseRate);prefs.putFloat("fMed",s.baseline.focusMedian);prefs.putFloat("fLap",s.baseline.focusLapseRate);prefs.putFloat("rErr",s.baseline.rhythmError);}
void Storage::saveSettings(){prefs.putBool("sound",settings.sound);prefs.putBool("led",settings.led);prefs.putUChar("length",settings.length);prefs.putUChar("trials",settings.quickTrials);prefs.putUShort("lapse",settings.lapseMs);} void Storage::resetStats(Stats&s){s=Stats();save(s);} void Storage::resetBaseline(Stats&s){s.baseline=Baseline();save(s);}
